import React, { useState, useEffect } from "react";
import { Form, Button, Col, Row } from "react-bootstrap";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import Header from "../../components/Headers/Header";
import ReactQuill from "react-quill";
import "react-quill/dist/quill.snow.css";

const EditDrug = () => {
    const { id } = useParams();
    const navigate = useNavigate();

    const [drug, setDrug] = useState({
        medicine_code: "",
        medicine_name: "",
        medicine_type_id: "",
        medicine_type_name: "",
        price: "",
        unit: "",
        description: "",
    });

    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    const fetchMedicine = async () => {
        try {
            const response = await axios.get(`http://localhost:5001/api/medicine/${id}`);
            console.log("Fetched drug data:", response.data);

            if (response.data) {
                setDrug((prev) => ({
                    ...prev,
                    medicine_code: response.data.medicine_code || "",
                    medicine_name: response.data.medicine_name || "",
                    medicine_type_id: response.data.medicine_type_id ? response.data.medicine_type_id.toString() : "",
                    medicine_type_name: response.data.medicine_type_name || "",
                    price: response.data.price ? response.data.price.toString() : "",
                    unit: response.data.unit || "",
                    description: response.data.description || "",
                }));
            }
        } catch (error) {
            console.error("Lỗi khi lấy dữ liệu thuốc:", error);
            setError("Không tìm thấy thuốc hoặc có lỗi khi tải dữ liệu.");
        } finally {
            setLoading(false);
        }
    };


    // Handle input change
    const handleChange = (e) => {
        const { name, value } = e.target;
        setDrug({ ...drug, [name]: value });
    };

    // Handle description change (ReactQuill)
    const handleDescriptionChange = (value) => {
        setDrug({ ...drug, description: value });
    };

    // Handle form submission
    const handleUpdate = async (e) => {
        e.preventDefault();

        // Form validation
        if (
            !drug.medicine_code ||
            !drug.medicine_name ||
            !drug.medicine_type_id ||
            !drug.price ||
            !drug.unit ||
            !drug.description
        ) {
            alert("Vui lòng điền đầy đủ các trường bắt buộc!");
            return;
        }

        try {
            // Prepare data for update
            const updateData = {
                medicine_code: drug.medicine_code,
                medicine_name: drug.medicine_name,
                medicine_type_id: parseInt(drug.medicine_type_id),
                price: parseInt(drug.price),
                unit: drug.unit,
                description: drug.description,
            };

            console.log("Sending update data:", updateData);

            // Send PUT request with proper template literals
            await axios.put(`http://localhost:5001/api/medicine/${id}`, updateData);

            alert("Cập nhật thành công!");
            navigate("/drug");
        } catch (error) {
            console.error("Lỗi khi cập nhật thuốc:", error);
            // Fixed template literal syntax
            alert(`Cập nhật thất bại! Lỗi: ${error.response?.data?.message || error.message}`);
        }
    };

    const handleCancel = () => {
        navigate("/drug");
    };

    if (loading) return <p>Đang tải dữ liệu...</p>;
    if (error) return <p style={{ color: "red" }}>{error}</p>;

    return (
        <>
            <Header />
            <div className="container mt-4">
                <h4 className="mb-4" style={{ fontSize: "28px", fontWeight: "bold" }}>
                    Chỉnh sửa thuốc
                </h4>
                <Form onSubmit={handleUpdate}>
                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineCode">
                                <Form.Label>
                                    Mã thuốc <span style={{ color: "red" }}>*</span>
                                </Form.Label>
                                <Form.Control
                                    type="text"
                                    placeholder="Mã thuốc (VD: MED002)"
                                    name="medicine_code"
                                    value={drug.medicine_code}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="medicineName">
                                <Form.Label>
                                    Tên thuốc <span style={{ color: "red" }}>*</span>
                                </Form.Label>
                                <Form.Control
                                    type="text"
                                    placeholder="Tên thuốc"
                                    name="medicine_name"
                                    value={drug.medicine_name}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineTypeId">
                                <Form.Label>
                                    ID loại thuốc <span style={{ color: "red" }}>*</span>
                                </Form.Label>
                                <Form.Control
                                    type="number"
                                    placeholder="ID loại thuốc (VD: 1)"
                                    name="medicine_type_id"
                                    value={drug.medicine_type_id}
                                    onChange={handleChange}
                                    required
                                />
                                <Form.Text muted>
                                    (Loại thuốc hiện tại: {drug.medicine_type_name})
                                </Form.Text>
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="drugPrice">
                                <Form.Label>
                                    Giá <span style={{ color: "red" }}>*</span>
                                </Form.Label>
                                <Form.Control
                                    type="number"
                                    placeholder="Giá (VNĐ)"
                                    name="price"
                                    value={drug.price}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="drugUnit">
                                <Form.Label>
                                    Đơn vị <span style={{ color: "red" }}>*</span>
                                </Form.Label>
                                <Form.Control
                                    type="text"
                                    placeholder="Đơn vị (VD: viên)"
                                    name="unit"
                                    value={drug.unit}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Form.Group controlId="drugDescription" className="mb-4">
                        <Form.Label>
                            Mô tả <span style={{ color: "red" }}>*</span>
                        </Form.Label>
                        <ReactQuill
                            theme="snow"
                            value={drug.description}
                            onChange={handleDescriptionChange}
                            placeholder="Nhập mô tả..."
                            required
                        />
                    </Form.Group>

                    <div className="d-flex justify-content-end">
                        <Button variant="danger" onClick={handleCancel} className="me-2">
                            Quay lại
                        </Button>
                        <Button variant="primary" type="submit">
                            Lưu lại
                        </Button>
                    </div>
                </Form>
            </div>
        </>
    );
};

export default EditDrug;
